{
  "children": [
    {
      "name": "RegisterPatient",
      "purpose": "Register a new patient in the system",
      "behavior": "Extract patient details from input, validate uniqueness, store in patients data store, and return success or error",
      "boundary": {
        "in_scope": [
          "patient registration",
          "input validation",
          "data store write"
        ],
        "out_of_scope": [
          "appointment booking",
          "record retrieval",
          "profile update"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient registration details"
      ],
      "semantic_outputs": [
        "result: JSON with success status, patient ID, and message"
      ],
      "preconditions": [
        "input contains valid patient data",
        "patient does not already exist"
      ],
      "postconditions": [
        "patient record created in patients data store"
      ],
      "guarantees": [
        "patient ID is unique",
        "registration is atomic"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "patient_data",
          "type": "dict",
          "description": "Patient registration details (name, age, contact, etc.)",
          "source": "parent input (input field)"
        }
      ],
      "outputs": [
        {
          "name": "registration_result",
          "type": "dict",
          "description": "Result with success status, patient ID, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def RegisterPatient(patient_data: dict) -> dict"
    },
    {
      "name": "BookAppointment",
      "purpose": "Book an appointment for a registered patient",
      "behavior": "Extract patient ID and appointment details from input, verify patient exists, check slot availability, store appointment in appointments data store, and return confirmation",
      "boundary": {
        "in_scope": [
          "appointment booking",
          "patient existence check",
          "slot validation",
          "data store write"
        ],
        "out_of_scope": [
          "patient registration",
          "record retrieval",
          "profile update"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient ID and appointment details"
      ],
      "semantic_outputs": [
        "result: JSON with success status, appointment ID, and message"
      ],
      "preconditions": [
        "patient is registered",
        "appointment slot is available"
      ],
      "postconditions": [
        "appointment record created in appointments data store"
      ],
      "guarantees": [
        "appointment is unique",
        "booking is atomic"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "appointment_data",
          "type": "dict",
          "description": "Appointment details (patient_id, date, time, doctor, etc.)",
          "source": "parent input (input field)"
        }
      ],
      "outputs": [
        {
          "name": "booking_result",
          "type": "dict",
          "description": "Result with success status, appointment ID, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def BookAppointment(appointment_data: dict) -> dict"
    },
    {
      "name": "GetPatientRecords",
      "purpose": "Retrieve medical records for a patient",
      "behavior": "Extract patient ID from input, verify patient exists, read records from patients data store (append-only), and return records",
      "boundary": {
        "in_scope": [
          "record retrieval",
          "patient existence check",
          "data store read"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "profile update"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient ID"
      ],
      "semantic_outputs": [
        "result: JSON with success status, records data, and message"
      ],
      "preconditions": [
        "patient is registered"
      ],
      "postconditions": [
        "records are read without modification"
      ],
      "guarantees": [
        "records are append-only",
        "read is consistent"
      ],
      "composition_role": "query",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "patient_id",
          "type": "str",
          "description": "Unique identifier for the patient",
          "source": "parent input (input field)"
        }
      ],
      "outputs": [
        {
          "name": "records_result",
          "type": "dict",
          "description": "Result with success status, records list, and message",
          "consumer": "parent"
        }
      ],
      "signature": "def GetPatientRecords(patient_id: str) -> dict"
    },
    {
      "name": "UpdatePatientProfile",
      "purpose": "Update a patient's profile information",
      "behavior": "Extract patient ID and updated fields from input, verify patient exists, update profile in patients data store, and return success",
      "boundary": {
        "in_scope": [
          "profile update",
          "patient existence check",
          "data store write"
        ],
        "out_of_scope": [
          "registration",
          "appointment booking",
          "record retrieval"
        ]
      },
      "semantic_inputs": [
        "input: JSON with patient ID and updated profile fields"
      ],
      "semantic_outputs": [
        "result: JSON with success status and message"
      ],
      "preconditions": [
        "patient is registered",
        "input contains valid update fields"
      ],
      "postconditions": [
        "patient profile updated in patients data store"
      ],
      "guarantees": [
        "update is atomic",
        "profile consistency maintained"
      ],
      "composition_role": "mutate",
      "stop_decompose": false,
      "stop_reason": "",
      "inputs": [
        {
          "name": "update_data",
          "type": "dict",
          "description": "Patient ID and updated profile fields",
          "source": "parent input (input field)"
        }
      ],
      "outputs": [
        {
          "name": "update_result",
          "type": "dict",
          "description": "Result with success status and message",
          "consumer": "parent"
        }
      ],
      "signature": "def UpdatePatientProfile(update_data: dict) -> dict"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {
      "input": "RegisterPatient, BookAppointment, GetPatientRecords, UpdatePatientProfile"
    },
    "parent_outputs_produced_by": {
      "output": "RegisterPatient, BookAppointment, GetPatientRecords, UpdatePatientProfile"
    }
  },
  "dataflow_edges": [
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "RegisterPatient",
      "to_input": "patient_data",
      "note": "parent routes registration command to RegisterPatient"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "BookAppointment",
      "to_input": "appointment_data",
      "note": "parent routes booking command to BookAppointment"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "GetPatientRecords",
      "to_input": "patient_id",
      "note": "parent routes records command to GetPatientRecords"
    },
    {
      "from_node": "parent",
      "from_output": "input",
      "to_node": "UpdatePatientProfile",
      "to_input": "update_data",
      "note": "parent routes update command to UpdatePatientProfile"
    },
    {
      "from_node": "RegisterPatient",
      "from_output": "registration_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "RegisterPatient returns result to parent"
    },
    {
      "from_node": "BookAppointment",
      "from_output": "booking_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "BookAppointment returns result to parent"
    },
    {
      "from_node": "GetPatientRecords",
      "from_output": "records_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "GetPatientRecords returns result to parent"
    },
    {
      "from_node": "UpdatePatientProfile",
      "from_output": "update_result",
      "to_node": "parent",
      "to_input": "output",
      "note": "UpdatePatientProfile returns result to parent"
    }
  ]
}
